Javascript.validate:
var description = Services.getValue(REF_DATA_XPATH + "/HasPart20ClaimantSettledJudgmentList/HasPart20ClaimantSettledJudgment[./Value = " + HasPart20ClaimantSettledJudgment.dataBinding + "]/Description");
var valueTest = Services.getValue( REF_DATA_XPATH + "/HasPart20ClaimantSettledJudgmentList/HasPart20ClaimantSettledJudgment[./Description = " + HasPart20ClaimantSettledJudgment.dataBinding + "]/Value" );
if (description == null && valueTest == null)
{
	// This is not a valid value - see list of Values
	return ErrorCode.getErrorCode("CaseMan_Reports_Invalid_LOV_Msg");
}
else
{
	return null;
}

Javascript.isReadOnly:
var referralReason = Services.getValue(ReferralReason.dataBinding);
var valueTest = Services.getValue( REF_DATA_XPATH + "/ReferralReasonList/ReferralReason[./Description = " + ReferralReason.dataBinding + "]/Value" );
if (referralReason == "JDG" || valueTest == "JDG")
{
	return false;
}
else
{
	return true;
}

Javascript.transformToDisplay:
var description = Services.getValue( REF_DATA_XPATH + "/HasPart20ClaimantSettledJudgmentList/HasPart20ClaimantSettledJudgment[./Value = " + HasPart20ClaimantSettledJudgment.dataBinding + "]/Description" );
if (description != null)
{
	return description;
}
else
{
	return value;
}

